import type { Locale } from "@/i18n/config";

/** One quiz question. `answer` is the 0-based index of the correct option. */
export type QuizQuestion = {
  id: string;
  theme: string;
  q: string;
  options: string[];
  answer: number;
  tip: string;
};

/**
 * The 150-question pool (French source of truth). The quiz draws a random
 * subset per game. Other locales fall back to FR until translated — add an
 * `en`/`de`/`es` array here to localise.
 */
const fr: QuizQuestion[] = [
  { id: "seo-01", theme: "seo", q: "Que signifie l'acronyme « SEO » ?", options: ["Search Engine Optimization", "Social Engagement Online", "Server Efficiency Operation", "Site Edition Officielle"], answer: 0, tip: "Le saviez-vous ? Le SEO regroupe tout ce qui rend un site visible sur Google sans payer la moindre publicité — un actif qui travaille pour vous 24h/24." },
  { id: "seo-02", theme: "seo", q: "Une internaute tape « acheter chaussures de running Luxembourg ». Quelle est son intention de recherche ?", options: ["Informationnelle", "Navigationnelle", "Transactionnelle", "Comparative"], answer: 2, tip: "Le saviez-vous ? Identifier l'intention derrière chaque mot-clé permet de capter des visiteurs prêts à acheter, pas seulement à lire." },
  { id: "seo-03", theme: "seo", q: "Quel levier améliore le plus souvent la vitesse de chargement d'un site ?", options: ["Ajouter plus de polices web", "Multiplier les pop-ups", "Compresser et optimiser les images", "Augmenter le poids des vidéos en autoplay"], answer: 2, tip: "Le saviez-vous ? Les images représentent souvent plus de la moitié du poids d'une page : bien les optimiser peut diviser le temps de chargement par deux." },
  { id: "seo-04", theme: "seo", q: "À quoi sert le fichier robots.txt ?", options: ["À crypter les données du site", "À traduire automatiquement le site", "À accélérer le serveur", "À indiquer aux robots les pages à explorer ou non"], answer: 3, tip: "Le saviez-vous ? Un robots.txt mal configuré peut accidentellement cacher tout votre site à Google — l'erreur technique qui coûte le plus cher." },
  { id: "seo-05", theme: "seo", q: "Quelle balise s'affiche comme titre cliquable dans les résultats Google ?", options: ["La balise <h1>", "La balise <title>", "La balise meta description", "La balise alt"], answer: 1, tip: "Le saviez-vous ? Une balise title soignée est votre première publicité gratuite dans les résultats : c'est elle qui décide du clic." },
  { id: "seo-06", theme: "seo", q: "La meta description influence-t-elle directement le classement Google ?", options: ["Oui, c'est le facteur numéro un", "Non, mais elle influence le taux de clic", "Oui, elle double le trafic", "Non, elle est ignorée par tous"], answer: 1, tip: "Le saviez-vous ? La meta description ne fait pas grimper le classement, mais une bonne accroche peut largement augmenter le nombre de clics." },
  { id: "seo-07", theme: "seo", q: "Qu'est-ce qu'un « backlink » ?", options: ["Un lien interne entre deux pages du même site", "Le bouton retour du navigateur", "Une page d'erreur 404", "Un lien d'un autre site qui pointe vers le vôtre"], answer: 3, tip: "Le saviez-vous ? Aux yeux de Google, un backlink de qualité est un vote de confiance — quelques bons valent mieux que cent médiocres." },
  { id: "seo-08", theme: "seo", q: "Pour renforcer l'autorité d'un site, mieux vaut obtenir...", options: ["Quelques liens de sites reconnus et pertinents", "Mille liens issus de fermes à spam", "Cinq mille liens achetés en une nuit", "Des liens uniquement vers vos réseaux sociaux"], answer: 0, tip: "Le saviez-vous ? Acheter des liens en masse expose à une pénalité Google : la qualité et la pertinence battent toujours la quantité." },
  { id: "seo-09", theme: "seo", q: "Que désigne l'acronyme « SERP » ?", options: ["Search Engine Results Page", "Secure Email Routing Protocol", "Site Engine Ranking Power", "Social Engagement Rate Plan"], answer: 0, tip: "Le saviez-vous ? La SERP, c'est la page de résultats : seules les premières positions captent l'essentiel des clics." },
  { id: "seo-10", theme: "seo", q: "Que mesure le « LCP » (Largest Contentful Paint) ?", options: ["Le nombre de clics par page", "La taille du fichier CSS", "Le temps d'affichage du plus gros élément visible", "Le nombre de mots-clés ciblés"], answer: 2, tip: "Le saviez-vous ? Google recommande un LCP sous 2,5 secondes : au-delà, l'internaute s'impatiente et votre référencement en pâtit." },
  { id: "seo-11", theme: "seo", q: "Que pénalise le « CLS » (Cumulative Layout Shift) ?", options: ["Les sites jugés trop rapides", "Les images en haute résolution", "Les titres trop longs", "Les éléments qui bougent pendant le chargement"], answer: 3, tip: "Le saviez-vous ? Un bouton qui se décale au mauvais moment fait cliquer à côté — le CLS mesure justement cette instabilité visuelle." },
  { id: "seo-12", theme: "seo", q: "À quoi sert principalement Google Search Console ?", options: ["À héberger votre site", "À suivre la performance de votre site dans la recherche Google", "À créer des publicités payantes", "À gérer votre messagerie"], answer: 1, tip: "Le saviez-vous ? La Search Console est gratuite et vous dit exactement quelles requêtes amènent du trafic — une mine d'or souvent ignorée." },
  { id: "seo-13", theme: "seo", q: "Que désigne une requête de « longue traîne » (long tail) ?", options: ["Une requête très courte et ultra-concurrentielle", "Un mot-clé interdit par Google", "Une requête précise, peu concurrentielle mais très qualifiée", "Une faute de frappe fréquente"], answer: 2, tip: "Le saviez-vous ? Les requêtes longues attirent moins de monde mais des visiteurs bien plus proches de l'achat : un terrain idéal pour une PME." },
  { id: "seo-14", theme: "seo", q: "Pour un commerce à Luxembourg-Ville, quel outil est incontournable pour le référencement local ?", options: ["La fiche d'établissement Google Business Profile", "Un compte TikTok", "Un fichier PDF", "Une newsletter hebdomadaire"], answer: 0, tip: "Le saviez-vous ? Une fiche Google bien remplie peut faire apparaître votre commerce dans le pack local et sur Maps, là où cherchent vos voisins." },
  { id: "seo-15", theme: "seo", q: "Quel est l'effet des avis clients sur une fiche Google Business ?", options: ["Ils n'ont aucun effet sur le référencement", "Ils sont supprimés automatiquement après trente jours", "Ils nécessitent un abonnement payant", "Ils renforcent la visibilité locale et la confiance"], answer: 3, tip: "Le saviez-vous ? Répondre à chaque avis, même négatif, envoie un signal positif à Google et rassure vos futurs clients." },
  { id: "seo-16", theme: "seo", q: "Sur un site multilingue (FR/DE/EN), à quoi sert l'attribut « hreflang » ?", options: ["À traduire automatiquement les pages", "À indiquer à Google la langue et la région de chaque version", "À bloquer les visiteurs étrangers", "À accélérer la traduction"], answer: 1, tip: "Le saviez-vous ? Au Luxembourg, un hreflang bien posé évite que votre page allemande s'affiche à un francophone — essentiel sur un marché trilingue." },
  { id: "seo-17", theme: "seo", q: "À quoi sert l'attribut « alt » d'une image ?", options: ["À changer la couleur de l'image", "À compresser le fichier", "À décrire l'image pour l'accessibilité et le SEO", "À ajouter un filigrane"], answer: 2, tip: "Le saviez-vous ? Le texte alternatif aide à la fois les lecteurs d'écran et Google Images — deux sources de visiteurs souvent oubliées." },
  { id: "seo-18", theme: "seo", q: "Le passage en HTTPS (le cadenas dans la barre d'adresse) est...", options: ["Inutile pour le SEO", "Un signal de confiance pris en compte par Google", "Réservé aux banques", "Un ralentisseur de site"], answer: 1, tip: "Le saviez-vous ? Sans HTTPS, les navigateurs affichent « site non sécurisé » — de quoi faire fuir un visiteur avant même votre page d'accueil." },
  { id: "seo-19", theme: "seo", q: "À quoi sert la balise « rel=canonical » ?", options: ["À indiquer la version de référence d'une page en cas de contenu dupliqué", "À supprimer une page", "À créer un sitemap", "À forcer une redirection 301"], answer: 0, tip: "Le saviez-vous ? La balise canonical évite que Google se disperse entre plusieurs URL identiques et concentre l'autorité sur la bonne page." },
  { id: "seo-20", theme: "seo", q: "À quoi sert un fichier sitemap.xml ?", options: ["À dessiner le plan des bureaux", "À lister les pages importantes pour faciliter l'exploration", "À héberger les images", "À bloquer l'accès à Google"], answer: 1, tip: "Le saviez-vous ? Un sitemap à jour aide Google à découvrir vos nouvelles pages plus vite — précieux quand vous publiez régulièrement." },
  { id: "geo-01", theme: "geo", q: "Que signifie l'acronyme « GEO » dans le marketing digital récent ?", options: ["Geographic Edge Optimization", "Generative Engine Optimization", "Global Email Outreach", "Google Earth Optimization"], answer: 1, tip: "Le saviez-vous ? Le GEO vise à faire citer votre marque par les IA comme ChatGPT ou Perplexity — la nouvelle frontière de la visibilité en ligne." },
  { id: "geo-02", theme: "geo", q: "Quelle est la différence principale entre SEO et GEO ?", options: ["Le SEO vise les liens bleus classiques, le GEO vise à être cité dans les réponses générées par l'IA", "Le GEO ne concerne que les images", "Le SEO est payant, le GEO gratuit", "Il n'y a aucune différence"], answer: 0, tip: "Le saviez-vous ? Le SEO vous place dans la liste des résultats, le GEO vous place directement dans la réponse de l'IA — deux objectifs complémentaires." },
  { id: "geo-03", theme: "geo", q: "Lequel de ces outils est un « moteur de réponse » génératif ?", options: ["Perplexity", "Microsoft Excel", "WeTransfer", "Trello"], answer: 0, tip: "Le saviez-vous ? Les moteurs de réponse comme Perplexity donnent une réponse synthétique et citent leurs sources : être l'une de ces sources devient un enjeu stratégique." },
  { id: "geo-04", theme: "geo", q: "Pour qu'une IA comme ChatGPT cite votre entreprise, il faut surtout...", options: ["Acheter des abonnements premium", "Désactiver tout votre SEO", "Publier un contenu clair, factuel et faisant autorité", "Afficher un logo plus grand"], answer: 2, tip: "Le saviez-vous ? Les IA privilégient les contenus précis et crédibles : la rigueur éditoriale devient un véritable levier de visibilité." },
  { id: "geo-05", theme: "geo", q: "À quoi servent les données structurées « Schema.org » ?", options: ["À décorer le site", "À aider les moteurs et les IA à comprendre le sens de votre contenu", "À bloquer les robots", "À compresser les pages"], answer: 1, tip: "Le saviez-vous ? Le balisage Schema.org traduit votre contenu en langage que machines et IA comprennent — un pont direct vers les réponses générées." },
  { id: "geo-06", theme: "geo", q: "À quoi sert le fichier « llms.txt » apparu récemment ?", options: ["À guider les modèles d'IA vers le contenu clé de votre site", "À héberger des vidéos", "À remplacer le HTML", "À gérer les cookies"], answer: 0, tip: "Le saviez-vous ? Pensé comme un robots.txt pour les IA, le llms.txt aide les modèles à repérer vos pages les plus utiles à citer." },
  { id: "geo-07", theme: "geo", q: "Un contenu « citable » par une IA est avant tout...", options: ["Long et vague", "Rempli de mots-clés répétés", "Caché derrière un formulaire", "Précis, sourcé et structuré en réponses claires"], answer: 3, tip: "Le saviez-vous ? Une IA reprend plus volontiers une affirmation chiffrée et sourcée qu'un paragraphe flou : la clarté est votre meilleure carte." },
  { id: "geo-08", theme: "geo", q: "Que sont les « AI Overviews » de Google ?", options: ["Des publicités vidéo", "Un antivirus intégré", "Des résumés générés par IA affichés en haut des résultats", "Un nouveau format d'image"], answer: 2, tip: "Le saviez-vous ? Les AI Overviews répondent directement en haut de page : y être cité devient aussi précieux que la première position classique." },
  { id: "geo-09", theme: "geo", q: "Les données structurées augmentent surtout les chances d'apparaître en...", options: ["Résultats enrichis (étoiles, FAQ, prix)", "Spam", "Bas de page uniquement", "Mode hors ligne"], answer: 0, tip: "Le saviez-vous ? Les résultats enrichis occupent plus de place dans la SERP et attirent l'œil — un avantage concurrentiel souvent sous-exploité." },
  { id: "geo-10", theme: "geo", q: "Que signifie une recherche « zero-click » ?", options: ["L'utilisateur clique sur dix résultats", "L'utilisateur quitte internet", "L'utilisateur obtient sa réponse sans cliquer sur le moindre site", "L'utilisateur achète aussitôt"], answer: 2, tip: "Le saviez-vous ? De plus en plus de recherches se terminent sans clic : être cité dans la réponse devient vital pour exister en ligne." },
  { id: "geo-11", theme: "geo", q: "Que valorise le principe « E-E-A-T » de Google ?", options: ["Expérience, Expertise, Autorité et Fiabilité (Trust)", "Email, Engagement, Ads et Trafic", "Erreurs, Espaces, Annonces et Tags", "Export, Excel, Audit et Test"], answer: 0, tip: "Le saviez-vous ? Démontrer une vraie expertise et inspirer confiance est aussi décisif pour Google que pour les IA qui s'appuient sur ses critères." },
  { id: "geo-12", theme: "geo", q: "Quel est un avantage du GEO par rapport à la publicité payante ?", options: ["Il garantit la première place payante", "Il supprime la concurrence", "Il fonctionne sans aucun contenu", "Une citation par une IA apporte une visibilité durable et crédible"], answer: 3, tip: "Le saviez-vous ? Une fois cité par une IA, vous gagnez en crédibilité sans payer au clic — un atout qui s'inscrit dans la durée." },
  { id: "geo-13", theme: "geo", q: "Pour être repris par les moteurs génératifs, mettre à jour régulièrement son contenu...", options: ["Est totalement inutile", "Renforce la pertinence et la fraîcheur perçue", "Fait baisser le classement", "Est interdit"], answer: 1, tip: "Le saviez-vous ? Les IA privilégient les informations récentes : un contenu daté est plus vite écarté au profit d'une source à jour." },
  { id: "geo-14", theme: "geo", q: "Structurer une page en questions/réponses (FAQ) aide une IA à...", options: ["Ralentir le site", "Extraire et citer facilement des réponses précises", "Cacher le contenu", "Bloquer l'indexation"], answer: 1, tip: "Le saviez-vous ? Le format question/réponse colle exactement à la façon dont les internautes interrogent les IA — d'où sa puissance en GEO." },
  { id: "geo-15", theme: "geo", q: "SEO et GEO sont-ils opposés ?", options: ["Oui, il faut choisir l'un ou l'autre", "Non, ils se complètent : une base SEO solide nourrit le GEO", "Oui, le GEO annule le SEO", "Non, mais le SEO est désormais mort"], answer: 1, tip: "Le saviez-vous ? Les IA puisent largement dans les contenus déjà bien référencés : investir dans le SEO, c'est déjà préparer le terrain du GEO." },
  { id: "web-01", theme: "web", q: "Que mesurent les « Core Web Vitals » de Google ?", options: ["La popularité d'un site sur les réseaux sociaux", "L'expérience réelle de chargement, d'interactivité et de stabilité visuelle", "Le nombre de mots-clés dans une page", "La quantité de visiteurs mensuels"], answer: 1, tip: "Le saviez-vous ? Les Core Web Vitals (LCP, INP, CLS) influencent votre référencement : chez vortx, on les optimise dès la conception." },
  { id: "web-02", theme: "web", q: "Que signifie l'approche « mobile-first » ?", options: ["Créer d'abord une application mobile", "Concevoir le site pour mobile avant de l'adapter aux grands écrans", "Interdire l'accès depuis un ordinateur", "Réserver le site aux utilisateurs de smartphones"], answer: 1, tip: "Le saviez-vous ? Plus de la moitié du trafic web est mobile : on conçoit donc d'abord pour le petit écran, puis on étend." },
  { id: "web-03", theme: "web", q: "À quoi sert le « S » dans HTTPS ?", options: ["Speed (la vitesse)", "Search (la recherche)", "Secure (le chiffrement de la connexion)", "Server (le serveur)"], answer: 2, tip: "Le saviez-vous ? Sans certificat SSL, les navigateurs affichent « Non sécurisé » et font fuir vos prospects." },
  { id: "web-04", theme: "web", q: "Quel est le principal atout d'un framework comme Next.js face à un WordPress classique ?", options: ["Il est toujours gratuit à héberger", "Il génère des pages rapides et optimisées sans plugins lourds", "Il n'a jamais besoin de maintenance", "Il rédige le contenu automatiquement"], answer: 1, tip: "Le saviez-vous ? Next.js produit des sites ultra-rapides par défaut : c'est notre socle technique chez vortx." },
  { id: "web-05", theme: "web", q: "En UX, que désigne la « hiérarchie visuelle » ?", options: ["L'ordre alphabétique des menus", "L'organisation des éléments pour guider l'œil vers l'essentiel", "Le classement des pages par date", "Le niveau d'accès des administrateurs"], answer: 1, tip: "Le saviez-vous ? Une bonne hiérarchie visuelle dirige le regard vers votre appel à l'action en une fraction de seconde." },
  { id: "web-06", theme: "web", q: "Combien d'objectifs principaux une landing page devrait-elle idéalement viser ?", options: ["Un seul, clair et unique", "Trois ou quatre, pour varier", "Autant que possible", "Aucun, c'est une vitrine"], answer: 0, tip: "Le saviez-vous ? Une page = un objectif : multiplier les boutons dilue les conversions au lieu de les augmenter." },
  { id: "web-07", theme: "web", q: "Que vise la norme WCAG ?", options: ["Le poids maximal des images", "L'accessibilité du web aux personnes en situation de handicap", "La vitesse des serveurs", "Le format des noms de domaine"], answer: 1, tip: "Le saviez-vous ? Un site accessible (WCAG) touche un public plus large et améliore aussi le SEO." },
  { id: "web-08", theme: "web", q: "Qu'est-ce qu'un site « responsive » ?", options: ["Un site qui répond aux e-mails automatiquement", "Un site qui s'adapte à toutes les tailles d'écran", "Un site hébergé sur plusieurs serveurs", "Un site qui se met à jour seul"], answer: 1, tip: "Le saviez-vous ? Le responsive design évite le zoom et le scroll horizontal, principaux irritants sur mobile." },
  { id: "web-09", theme: "web", q: "À quoi sert un CMS (Content Management System) ?", options: ["À héberger des e-mails", "À gérer et publier du contenu sans coder", "À sécuriser les paiements", "À compresser les images"], answer: 1, tip: "Le saviez-vous ? Un CMS bien intégré vous rend autonome sur vos contenus, sans dépendre du développeur pour chaque virgule." },
  { id: "web-10", theme: "web", q: "Pourquoi l'espace blanc (« white space ») est-il précieux en UI ?", options: ["Il réduit le poids du fichier", "Il aère la mise en page et améliore la lisibilité", "Il accélère le serveur", "Il économise de l'encre à l'impression"], answer: 1, tip: "Le saviez-vous ? L'espace blanc n'est pas du vide perdu : il met vos messages clés en valeur." },
  { id: "web-11", theme: "web", q: "Lors d'une refonte de site, quel risque faut-il absolument anticiper ?", options: ["Perdre le référencement existant faute de redirections", "Changer de couleur de logo", "Renommer l'entreprise", "Réduire le nombre d'employés"], answer: 0, tip: "Le saviez-vous ? Sans redirections 301, une refonte peut effacer des années de SEO : on planifie ça avant de migrer." },
  { id: "web-12", theme: "web", q: "Que désigne la « charge cognitive » en UX ?", options: ["Le poids des images d'une page", "L'effort mental demandé à l'utilisateur pour comprendre l'interface", "Le coût d'hébergement mensuel", "Le temps de chargement du serveur"], answer: 1, tip: "Le saviez-vous ? Moins l'utilisateur réfléchit, plus il agit : on simplifie chaque parcours pour réduire l'abandon." },
  { id: "web-13", theme: "web", q: "Quel format d'image est généralement le plus léger pour le web moderne ?", options: ["BMP", "WebP ou AVIF", "TIFF", "PNG non compressé"], answer: 1, tip: "Le saviez-vous ? Passer aux formats WebP/AVIF peut diviser le poids des images par deux, et accélérer d'autant la page." },
  { id: "web-14", theme: "web", q: "Pour un formulaire efficace, quelle bonne pratique s'impose ?", options: ["Demander un maximum d'informations d'emblée", "Réduire le nombre de champs au strict nécessaire", "Masquer le bouton d'envoi", "Désactiver l'autocomplétion"], answer: 1, tip: "Le saviez-vous ? Chaque champ en trop fait chuter le taux de complétion : on ne demande que l'essentiel." },
  { id: "web-15", theme: "web", q: "Que mesure le LCP (Largest Contentful Paint) ?", options: ["Le temps avant l'affichage du plus grand élément visible", "Le nombre de clics par visite", "La taille totale de la page", "Le délai d'envoi d'un formulaire"], answer: 0, tip: "Le saviez-vous ? Un bon LCP se situe sous 2,5 secondes : au-delà, les visiteurs partent avant même de voir l'offre." },
  { id: "web-16", theme: "web", q: "Pourquoi maintenir un design system (composants réutilisables) ?", options: ["Pour ralentir volontairement la production", "Pour garantir la cohérence visuelle et accélérer les évolutions", "Pour augmenter le poids du site", "Pour compliquer la maintenance"], answer: 1, tip: "Le saviez-vous ? Un design system assure une marque cohérente sur chaque page et fait gagner un temps précieux." },
  { id: "web-17", theme: "web", q: "Sur une boutique e-commerce, quel facteur réduit le plus l'abandon de panier ?", options: ["Un tunnel de commande simple et rassurant", "Plus de pop-ups publicitaires", "Une police d'écriture exotique", "Davantage d'étapes de vérification"], answer: 0, tip: "Le saviez-vous ? Frais cachés et inscription obligatoire sont les premières causes d'abandon de panier." },
  { id: "web-18", theme: "web", q: "Quel niveau de contraste texte/fond garantit une bonne lisibilité (WCAG AA, texte normal) ?", options: ["Au moins 4,5:1", "Exactement 1:1", "Maximum 2:1", "Le contraste n'a aucune importance"], answer: 0, tip: "Le saviez-vous ? Un contraste d'au moins 4,5:1 rend votre texte lisible pour tous, y compris en plein soleil sur mobile." },
  { id: "web-19", theme: "web", q: "Qu'est-ce que l'hébergement web ?", options: ["Le nom commercial du site", "L'espace serveur où vivent les fichiers du site, accessibles en ligne", "Le logiciel de design", "Le contrat avec une agence"], answer: 1, tip: "Le saviez-vous ? Un hébergement rapide et proche de vos visiteurs réduit les temps de chargement de façon mesurable." },
  { id: "web-20", theme: "web", q: "Que désigne le CLS (Cumulative Layout Shift) ?", options: ["Le nombre de pages indexées", "La stabilité visuelle, soit les sauts de mise en page pendant le chargement", "La vitesse du serveur", "Le taux de rebond"], answer: 1, tip: "Le saviez-vous ? Un CLS élevé fait « sauter » les boutons et provoque des clics ratés : on stabilise la mise en page dès le départ." },
  { id: "branding-01", theme: "branding", q: "Quelle qualité ne fait PAS partie d'un bon logo ?", options: ["Simple", "Mémorable", "Surchargé de détails", "Polyvalent"], answer: 2, tip: "Le saviez-vous ? Les meilleurs logos restent lisibles même réduits à la taille d'une favicon." },
  { id: "branding-02", theme: "branding", q: "Pour l'impression professionnelle, quel mode colorimétrique est utilisé ?", options: ["RVB", "CMJN", "HSL", "Pantone uniquement"], answer: 1, tip: "Le saviez-vous ? Un visuel pensé en RVB peut virer à l'impression : on prépare vos fichiers print en CMJN pour éviter les surprises." },
  { id: "branding-03", theme: "branding", q: "Quelle est la différence entre une image vectorielle et une image bitmap ?", options: ["Le vectoriel se redimensionne sans perte de qualité", "Le bitmap est toujours plus net", "Le vectoriel ne contient pas de couleurs", "Aucune, ce sont des synonymes"], answer: 0, tip: "Le saviez-vous ? Un logo vectoriel (SVG, AI) reste impeccable de la carte de visite au panneau publicitaire." },
  { id: "branding-04", theme: "branding", q: "À quoi sert une charte graphique (brand guidelines) ?", options: ["À fixer les prix des produits", "À définir les règles d'usage du logo, des couleurs et des typographies", "À gérer la comptabilité", "À héberger le site"], answer: 1, tip: "Le saviez-vous ? Une charte graphique garantit que votre marque reste identique, quel que soit le support ou le prestataire." },
  { id: "branding-05", theme: "branding", q: "Que sont les « fonds perdus » en impression ?", options: ["Une zone de couleur qui dépasse la coupe pour éviter les bords blancs", "Des fichiers égarés par l'imprimeur", "Une remise sur le papier", "Le verso non imprimé"], answer: 0, tip: "Le saviez-vous ? Sans fonds perdus, un léger décalage de découpe laisse une vilaine marge blanche sur vos cartes." },
  { id: "branding-06", theme: "branding", q: "Pourquoi la cohérence de marque est-elle stratégique ?", options: ["Elle réduit le coût du papier", "Elle renforce la reconnaissance et la confiance dans le temps", "Elle accélère le wifi", "Elle évite de payer des impôts"], answer: 1, tip: "Le saviez-vous ? Une marque cohérente sur tous les points de contact se mémorise et se reconnaît bien plus vite." },
  { id: "branding-07", theme: "branding", q: "Qu'appelle-t-on un logotype ?", options: ["Un logo composé uniquement du nom typographié", "Un symbole sans texte", "Un slogan publicitaire", "Une couleur de marque"], answer: 0, tip: "Le saviez-vous ? Logotype (le nom stylisé) et symbole se combinent souvent pour créer une identité flexible." },
  { id: "branding-08", theme: "branding", q: "En psychologie des couleurs, le bleu évoque le plus souvent…", options: ["L'urgence et le danger", "La confiance et le sérieux", "La gourmandise", "La fantaisie enfantine"], answer: 1, tip: "Le saviez-vous ? Le choix des couleurs n'est pas qu'esthétique : il oriente la perception de votre marque." },
  { id: "branding-09", theme: "branding", q: "Que désigne le « naming » en stratégie de marque ?", options: ["Le choix du nom de la marque ou du produit", "La mise en page d'un document", "La signature d'un contrat", "Le classement des concurrents"], answer: 0, tip: "Le saviez-vous ? Un bon nom est court, prononçable et disponible en nom de domaine : on vérifie tout cela en amont." },
  { id: "branding-10", theme: "branding", q: "Combien de familles typographiques principales suffisent généralement à une identité solide ?", options: ["Une à deux", "Au moins cinq", "Une dizaine", "Le plus possible"], answer: 0, tip: "Le saviez-vous ? Limiter à une ou deux polices renforce la cohérence et la lisibilité de votre marque." },
  { id: "branding-11", theme: "branding", q: "Qu'est-ce qu'un logo « intemporel » ?", options: ["Un logo animé en permanence", "Un logo qui ne suit pas les modes et vieillit bien", "Un logo qui change chaque année", "Un logo affiché sans horloge"], answer: 1, tip: "Le saviez-vous ? Un logo intemporel évite les refontes coûteuses tous les deux ans : on vise la durabilité, pas la tendance." },
  { id: "branding-12", theme: "branding", q: "Pourquoi un logo doit-il fonctionner en une seule couleur (monochrome) ?", options: ["Pour les contextes contraints : tampon, gravure, fax, fond sombre", "Parce que la couleur est interdite", "Pour économiser de l'électricité", "Parce que le noir est plus moderne"], answer: 0, tip: "Le saviez-vous ? Un logo qui tient en noir et blanc reste solide partout : c'est un test de robustesse incontournable." },
  { id: "branding-13", theme: "branding", q: "Que signifie qu'un logo soit « approprié » ?", options: ["Qu'il est protégé par un droit d'auteur", "Qu'il correspond au secteur et au public visé", "Qu'il appartient juridiquement à l'agence", "Qu'il est déposé à l'INPI"], answer: 1, tip: "Le saviez-vous ? Un logo ludique pour un cabinet d'avocats brouille le message : la pertinence prime sur le style." },
  { id: "branding-14", theme: "branding", q: "À quoi sert une « zone de protection » autour d'un logo ?", options: ["À réserver un espace vide qui préserve sa lisibilité", "À empêcher de le copier", "À indiquer sa version payante", "À afficher le copyright"], answer: 0, tip: "Le saviez-vous ? La zone de protection évite que textes ou images viennent étouffer votre logo, une règle clé de la charte." },
  { id: "branding-15", theme: "branding", q: "Qu'est-ce que l'identité de marque, au sens large ?", options: ["Uniquement le logo", "L'ensemble des éléments visuels et verbaux qui rendent la marque reconnaissable", "Le numéro d'immatriculation de l'entreprise", "La liste des clients"], answer: 1, tip: "Le saviez-vous ? L'identité de marque va bien au-delà du logo : couleurs, typographies, ton et images forment un tout cohérent." },
  { id: "leads-01", theme: "leads", q: "Dans un tunnel de conversion, que désigne le 'TOFU' (Top of the Funnel) ?", options: ["L'étape où le prospect signe le contrat", "La phase de découverte où l'on attire un large public encore peu qualifié", "Le moment où l'on relance un client perdu", "Le format de page de paiement"], answer: 1, tip: "Le saviez-vous ? Un bon TOFU nourrit tout le reste du tunnel : chez vortx, on calibre chaque étage du funnel avant de dépenser un euro en pub." },
  { id: "leads-02", theme: "leads", q: "Que signifie l'acronyme CRO en marketing digital ?", options: ["Customer Relationship Office", "Conversion Rate Optimization", "Cost Reduction Operation", "Content Ranking Order"], answer: 1, tip: "Le saviez-vous ? Le CRO consiste à transformer plus de visiteurs sans payer plus de trafic : souvent le levier le plus rentable d'un site." },
  { id: "leads-03", theme: "leads", q: "Quel est le principe d'un test A/B sur une landing page ?", options: ["Lancer deux campagnes sur deux pays différents", "Comparer deux versions d'un même élément pour garder la plus performante", "Doubler le budget publicitaire pendant deux jours", "Traduire la page en deux langues"], answer: 1, tip: "Le saviez-vous ? Changer un seul mot dans un titre peut faire varier le taux de conversion de façon mesurable : encore faut-il tester proprement, une variable à la fois." },
  { id: "leads-04", theme: "leads", q: "Quelle est la différence entre un MQL et un SQL ?", options: ["Le MQL est un lead jugé mûr par le marketing, le SQL est validé prêt pour la vente", "Le MQL coûte moins cher que le SQL", "Le SQL vient des réseaux sociaux, le MQL des emails", "Il n'y a aucune différence, ce sont des synonymes"], answer: 0, tip: "Le saviez-vous ? Aligner la définition d'un MQL entre marketing et commerciaux évite des dizaines de leads gaspillés chaque mois." },
  { id: "leads-05", theme: "leads", q: "Que mesure le CPL (coût par lead) ?", options: ["Le chiffre d'affaires généré par client", "Le montant moyen dépensé pour obtenir un contact qualifié", "Le nombre de clics par page", "La durée moyenne d'une visite"], answer: 1, tip: "Le saviez-vous ? Un CPL faible n'est pas toujours bon signe : mieux vaut un lead un peu plus cher mais qui se transforme réellement en client." },
  { id: "leads-06", theme: "leads", q: "Quelle pratique nuit le plus à la conversion d'une landing page de campagne ?", options: ["Un titre clair orienté bénéfice", "Une multitude de liens et de menus qui dispersent l'attention", "Un seul appel à l'action visible", "Une preuve sociale crédible"], answer: 1, tip: "Le saviez-vous ? Une landing page de campagne efficace n'a souvent qu'un seul chemin possible : l'action voulue. On supprime tout le reste." },
  { id: "leads-07", theme: "leads", q: "Qu'est-ce qu'un bon CTA (call-to-action) ?", options: ["Un long paragraphe explicatif en bas de page", "Une formulation vague comme 'Cliquez ici'", "Une action claire et orientée bénéfice, comme 'Réserver mon audit gratuit'", "Une image décorative sans lien"], answer: 2, tip: "Le saviez-vous ? Un CTA qui dit ce que le visiteur va obtenir convertit mieux qu'un CTA qui dit ce qu'il doit faire." },
  { id: "leads-08", theme: "leads", q: "En quoi consiste le lead nurturing ?", options: ["Acheter des bases de données d'emails", "Entretenir la relation avec un prospect pas encore prêt à acheter", "Supprimer les contacts inactifs", "Augmenter le budget publicitaire"], answer: 1, tip: "Le saviez-vous ? La majorité des prospects ne sont pas prêts à acheter au premier contact : un nurturing bien pensé les ramène au bon moment." },
  { id: "leads-09", theme: "leads", q: "À quoi sert le marketing automation ?", options: ["À envoyer manuellement chaque email un par un", "À déclencher des messages et actions selon le comportement des contacts", "À bloquer les concurrents sur les réseaux", "À rédiger automatiquement les contrats clients"], answer: 1, tip: "Le saviez-vous ? Un scénario automatisé travaille pour vous 24h/24 : bien réglé, il relance les bons prospects sans intervention humaine." },
  { id: "leads-10", theme: "leads", q: "Comment optimise-t-on généralement un formulaire de génération de leads ?", options: ["En ajoutant le plus de champs possible", "En réduisant les champs à l'essentiel pour limiter les frictions", "En rendant tous les champs obligatoires", "En masquant le bouton d'envoi"], answer: 1, tip: "Le saviez-vous ? Chaque champ supplémentaire fait souvent baisser le taux de complétion : on ne demande que ce dont on a vraiment besoin." },
  { id: "leads-11", theme: "leads", q: "Que permet le lead scoring ?", options: ["De classer les prospects selon leur niveau d'intérêt et de maturité", "De calculer le salaire des commerciaux", "De noter la qualité graphique d'un site", "De mesurer la vitesse de chargement d'une page"], answer: 0, tip: "Le saviez-vous ? En attribuant des points aux actions clés (visite tarifs, ouverture d'email...), on repère les prospects chauds avant les concurrents." },
  { id: "leads-12", theme: "leads", q: "Dans un funnel, où se situe l'étape BOFU (Bottom of the Funnel) ?", options: ["Tout en haut, pour la notoriété", "Au milieu, pour la considération", "Tout en bas, au moment de la décision d'achat", "En dehors du tunnel"], answer: 2, tip: "Le saviez-vous ? Le contenu BOFU (démo, devis, étude de cas) doit lever les derniers freins : c'est là que se joue la signature." },
  { id: "leads-13", theme: "leads", q: "Quel principe du copywriting persuasif est le plus efficace sur une page de vente ?", options: ["Parler longuement de l'histoire de l'entreprise", "Mettre en avant les bénéfices pour le client plutôt que les caractéristiques", "Utiliser un maximum de jargon technique", "Éviter tout chiffre concret"], answer: 1, tip: "Le saviez-vous ? Les gens n'achètent pas une perceuse, mais un trou dans le mur : un bon texte vend le résultat, pas la fonctionnalité." },
  { id: "leads-14", theme: "leads", q: "Qu'est-ce qui améliore le plus le taux d'ouverture d'un email marketing ?", options: ["La couleur du bouton dans l'email", "Un objet pertinent et un nom d'expéditeur reconnaissable", "Le nombre d'images intégrées", "La longueur du pied de page"], answer: 1, tip: "Le saviez-vous ? L'objet et l'expéditeur décident de l'ouverture avant même que le contenu ne soit lu : c'est la première bataille de l'email." },
  { id: "leads-15", theme: "leads", q: "Une page reçoit 2 000 visiteurs et génère 60 leads. Quel est son taux de conversion ?", options: ["6 %", "0,3 %", "3 %", "30 %"], answer: 2, tip: "Le saviez-vous ? Taux de conversion = conversions ÷ visiteurs. Ici 60 ÷ 2 000 = 3 %, un repère utile pour juger une page." },
  { id: "leads-16", theme: "leads", q: "Quel type de contenu est le plus adapté à l'étape MOFU (considération) ?", options: ["Un article de blog de découverte très généraliste", "Un comparatif, un webinaire ou une étude de cas qui aide à évaluer", "Un bon de réduction de dernière minute", "Une publicité de pure notoriété"], answer: 1, tip: "Le saviez-vous ? Au MOFU, le prospect compare : lui donner des comparatifs et des cas concrets le rapproche naturellement de la décision." },
  { id: "leads-17", theme: "leads", q: "Que mesure le CPA (coût par acquisition) ?", options: ["Le coût pour générer un simple clic", "Le coût moyen pour obtenir une conversion ou un client", "Le coût d'hébergement du site", "Le coût d'un test A/B"], answer: 1, tip: "Le saviez-vous ? Le CPA relie la dépense au résultat final : c'est l'indicateur qui parle vraiment aux dirigeants, plus que le coût du clic." },
  { id: "leads-18", theme: "leads", q: "Pourquoi créer une landing page dédiée plutôt qu'envoyer le trafic publicitaire vers la page d'accueil ?", options: ["Parce que c'est obligatoire chez Google", "Parce qu'un message aligné sur l'annonce et un seul objectif convertissent mieux", "Parce que la page d'accueil charge plus lentement", "Parce que c'est moins cher à héberger"], answer: 1, tip: "Le saviez-vous ? La cohérence entre l'annonce et la page d'arrivée est l'un des plus gros leviers de conversion d'une campagne payante." },
  { id: "leads-19", theme: "leads", q: "Quelle technique renforce la confiance et aide à la conversion d'un prospect hésitant ?", options: ["Masquer les mentions légales", "Afficher des preuves sociales : avis, logos clients, résultats chiffrés", "Multiplier les pop-ups", "Supprimer la page de contact"], answer: 1, tip: "Le saviez-vous ? Une preuve sociale crédible rassure plus qu'un argumentaire : montrer des résultats réels vaut mieux que de se déclarer 'leader'." },
  { id: "leads-20", theme: "leads", q: "Quel est le risque d'une séquence de nurturing trop fréquente ?", options: ["Une meilleure délivrabilité", "Une hausse des désabonnements et des plaintes spam", "Une baisse du coût par lead", "Une amélioration automatique du scoring"], answer: 1, tip: "Le saviez-vous ? Trop d'emails fatigue la liste et abîme la délivrabilité : le bon rythme entretient l'intérêt sans lasser." },
  { id: "ads-01", theme: "ads", q: "Que signifie le ROAS en publicité en ligne ?", options: ["Le retour sur les dépenses publicitaires (revenu généré / budget dépensé)", "Le nombre total de clics reçus", "Le rang moyen de l'annonce", "Le coût d'un abonnement à la plateforme"], answer: 0, tip: "Le saviez-vous ? Un ROAS de 4 signifie 4 € de chiffre d'affaires pour 1 € investi : c'est la boussole de toute campagne rentable." },
  { id: "ads-02", theme: "ads", q: "À quoi correspond le CPC ?", options: ["Le coût par conversion", "Le coût payé à chaque clic sur l'annonce", "Le coût pour mille impressions", "Le coût de création du visuel"], answer: 1, tip: "Le saviez-vous ? Sur Google Ads, vous payez le plus souvent au clic, pas à l'affichage : optimiser la pertinence fait baisser ce coût." },
  { id: "ads-03", theme: "ads", q: "Sur Google Ads, qu'influence directement le Quality Score (niveau de qualité) ?", options: ["La couleur de l'annonce", "Le coût par clic et la position de l'annonce", "Le nombre de mots dans le titre du site", "Le fuseau horaire de diffusion"], answer: 1, tip: "Le saviez-vous ? Un bon Quality Score peut réduire votre CPC à enchère égale : pertinence annonce + page de destination paient vraiment." },
  { id: "ads-04", theme: "ads", q: "Qu'est-ce qu'une campagne Performance Max sur Google Ads ?", options: ["Une campagne uniquement sur le réseau de recherche", "Une campagne automatisée diffusant sur tous les inventaires Google (Search, Display, YouTube, Maps...)", "Une campagne réservée aux applications mobiles", "Une campagne d'emailing"], answer: 1, tip: "Le saviez-vous ? Performance Max s'appuie fortement sur l'automatisation : la qualité des données de conversion qu'on lui fournit fait toute la différence." },
  { id: "ads-05", theme: "ads", q: "En quoi consiste le retargeting (reciblage) ?", options: ["Cibler uniquement de nouveaux prospects", "Réafficher des annonces aux personnes ayant déjà interagi avec votre marque", "Changer le ciblage géographique chaque jour", "Supprimer les audiences existantes"], answer: 1, tip: "Le saviez-vous ? Relancer un visiteur qui connaît déjà votre marque coûte souvent bien moins cher que d'en conquérir un nouveau." },
  { id: "ads-06", theme: "ads", q: "Quelle différence majeure entre SEA et SEO ?", options: ["Le SEA est payant et donne des résultats immédiats, le SEO est organique et s'installe dans la durée", "Le SEO est payant, le SEA est gratuit", "Les deux donnent des résultats instantanés", "Le SEA ne concerne que les réseaux sociaux"], answer: 0, tip: "Le saviez-vous ? SEA et SEO ne s'opposent pas : la pub achète de la visibilité immédiate pendant que le référencement naturel se construit." },
  { id: "ads-07", theme: "ads", q: "Pourquoi LinkedIn Ads est-il souvent privilégié en B2B malgré un CPC élevé ?", options: ["Parce que les clics y sont gratuits", "Parce qu'il permet un ciblage précis par fonction, secteur et taille d'entreprise", "Parce qu'il garantit des ventes immédiates", "Parce qu'il interdit la concurrence"], answer: 1, tip: "Le saviez-vous ? En B2B, payer plus cher le clic peut être rentable si l'on touche exactement le décideur visé plutôt qu'une audience large." },
  { id: "ads-08", theme: "ads", q: "Qu'est-ce qu'une audience lookalike (similaire) sur Meta Ads ?", options: ["Une liste de vos clients existants", "Une audience de nouvelles personnes ressemblant à vos meilleurs clients", "Les personnes qui ont masqué vos annonces", "Vos abonnés actuels uniquement"], answer: 1, tip: "Le saviez-vous ? Une lookalike construite à partir de vos vrais clients est souvent bien plus performante qu'un ciblage par centres d'intérêt." },
  { id: "ads-09", theme: "ads", q: "Quel type de produit la publicité Google Shopping met-elle en avant ?", options: ["Des articles de blog", "Des fiches produits avec image, prix et marchand", "Des vidéos de marque", "Des offres d'emploi"], answer: 1, tip: "Le saviez-vous ? Shopping s'appuie sur la qualité du flux produit : titres et images bien optimisés font grimper la visibilité sans toucher aux enchères." },
  { id: "ads-10", theme: "ads", q: "Pour quel objectif la publicité YouTube est-elle la plus naturellement adaptée ?", options: ["La signature immédiate d'un contrat", "La notoriété et la considération via le format vidéo", "Le remplacement total du SEO", "La gestion comptable des campagnes"], answer: 1, tip: "Le saviez-vous ? La vidéo excelle pour faire connaître et expliquer : couplée au retargeting, elle prépare le terrain aux campagnes de conversion." },
  { id: "ads-11", theme: "ads", q: "Que désigne l'ABM (Account-Based Marketing) ?", options: ["Une stratégie ciblant des comptes/entreprises précis plutôt qu'un large public", "Un format publicitaire automatique", "Une méthode de comptabilité analytique", "Un type d'enchère Google"], answer: 0, tip: "Le saviez-vous ? En ABM, on traite quelques comptes stratégiques comme des marchés à part entière : idéal pour les ventes B2B à fort enjeu." },
  { id: "ads-12", theme: "ads", q: "Que fait une stratégie d'enchères 'Maximiser les conversions' sur Google Ads ?", options: ["Elle vise le maximum de clics, peu importe les conversions", "Elle ajuste automatiquement les enchères pour obtenir le plus de conversions possible dans le budget", "Elle fixe un CPC manuel constant", "Elle coupe la diffusion la nuit"], answer: 1, tip: "Le saviez-vous ? Les enchères automatiques ont besoin de données fiables : sans bon suivi des conversions, l'algorithme optimise à l'aveugle." },
  { id: "ads-13", theme: "ads", q: "Pourquoi le suivi des conversions est-il indispensable avant de lancer des campagnes ?", options: ["Pour faire joli dans les rapports", "Pour mesurer ce qui rapporte vraiment et permettre à l'algorithme d'optimiser", "Parce que Google l'impose à tous", "Pour augmenter le CPC volontairement"], answer: 1, tip: "Le saviez-vous ? Sans suivi des conversions, on pilote une campagne sans tableau de bord : c'est la première chose qu'on vérifie chez vortx." },
  { id: "ads-14", theme: "ads", q: "À quoi sert un budget de test au lancement d'une campagne ?", options: ["À dépenser le maximum dès le premier jour", "À récolter des données pour identifier les angles, audiences et créas qui marchent", "À éviter de mesurer les résultats", "À payer la plateforme à l'avance"], answer: 1, tip: "Le saviez-vous ? Une phase de test évite de scaler une mauvaise campagne : on investit d'abord pour apprendre, puis on amplifie ce qui fonctionne." },
  { id: "ads-15", theme: "ads", q: "Que mesure le CTR (taux de clics) d'une annonce ?", options: ["Le pourcentage d'impressions qui ont donné lieu à un clic", "Le coût total de la campagne", "Le nombre de ventes réalisées", "La durée de visionnage d'une vidéo"], answer: 0, tip: "Le saviez-vous ? Un CTR élevé signale une annonce pertinente pour son audience, ce qui peut aussi améliorer le niveau de qualité et baisser les coûts." },
  { id: "ads-16", theme: "ads", q: "Quelle est la particularité de Threads par rapport aux autres réseaux de Meta ?", options: ["C'est une plateforme de paiement", "C'est un réseau axé sur les conversations textuelles, lié à l'écosystème Instagram", "C'est un outil de comptabilité", "C'est un moteur de recherche"], answer: 1, tip: "Le saviez-vous ? Les jeunes plateformes comme Threads offrent parfois une visibilité organique plus accessible : un terrain à tester selon votre cible." },
  { id: "ads-17", theme: "ads", q: "Quel est le risque d'un ciblage publicitaire trop large ?", options: ["Un coût par résultat plus faible automatiquement", "Diffuser le budget à des personnes peu pertinentes et diluer la performance", "Une meilleure pertinence des annonces", "Une hausse garantie du ROAS"], answer: 1, tip: "Le saviez-vous ? Un ciblage trop large gaspille le budget ; trop étroit l'étouffe : trouver le bon équilibre est tout l'art du média planning." },
  { id: "ads-18", theme: "ads", q: "Sur le réseau de recherche Google, que fait le type de correspondance 'exacte' d'un mot-clé ?", options: ["Il diffuse sur n'importe quelle recherche vaguement liée", "Il limite la diffusion aux requêtes très proches de l'intention du mot-clé", "Il bloque toutes les annonces concurrentes", "Il transforme le mot-clé en hashtag"], answer: 1, tip: "Le saviez-vous ? La correspondance exacte protège votre budget des requêtes hors sujet : précieux pour les mots-clés à forte intention d'achat." },
  { id: "ads-19", theme: "ads", q: "Une campagne dépense 1 000 € et génère 5 000 € de chiffre d'affaires. Quel est le ROAS ?", options: ["50 %", "5 (soit 500 %)", "0,2", "20 %"], answer: 1, tip: "Le saviez-vous ? ROAS = revenu ÷ dépense, ici 5 000 ÷ 1 000 = 5. Reste à vérifier que la marge derrière ce chiffre est bien rentable." },
  { id: "ads-20", theme: "ads", q: "À quoi sert un pixel (balise de suivi) installé sur un site ?", options: ["À accélérer le chargement des pages", "À enregistrer les actions des visiteurs pour mesurer et optimiser les campagnes", "À héberger les images du site", "À traduire automatiquement le contenu"], answer: 1, tip: "Le saviez-vous ? Le pixel est le pont entre votre site et les régies publicitaires : mal posé, il fausse toutes vos décisions d'optimisation." },
  { id: "ia-01", theme: "ia", q: "À quoi sert un outil comme Make, n8n ou Zapier ?", options: ["Connecter vos applis et automatiser des tâches répétitives", "Héberger votre site web", "Concevoir un logo", "Remplacer votre comptable"], answer: 0, tip: "Le saviez-vous ? Un seul scénario d'automatisation bien réglé peut économiser plusieurs heures par semaine — chez vortx, on commence souvent par les tâches que personne n'aime faire." },
  { id: "ia-02", theme: "ia", q: "Que désigne le sigle RAG dans un assistant IA ?", options: ["Retrieval-Augmented Generation", "Rapid Agent Gateway", "Random Answer Generator", "Real-time Audio Grid"], answer: 0, tip: "Le saviez-vous ? Le RAG permet à un assistant de répondre à partir de VOS documents — un chatbot vortx nourri de votre base de connaissances cesse d'inventer." },
  { id: "ia-03", theme: "ia", q: "Quel est l'intérêt principal d'un webhook entre deux logiciels ?", options: ["Déclencher une action automatiquement dès qu'un événement se produit", "Sauvegarder vos mots de passe", "Augmenter la vitesse de votre Wi-Fi", "Crypter vos e-mails"], answer: 0, tip: "Le saviez-vous ? Un webhook envoie l'info en temps réel plutôt que d'attendre une vérification toutes les heures — idéal pour synchroniser un formulaire avec votre CRM." },
  { id: "ia-04", theme: "ia", q: "Pourquoi garder une validation humaine dans un workflow IA sensible ?", options: ["Pour vérifier et arbitrer avant qu'une action critique parte", "Parce que l'IA est interdite en Europe", "Pour ralentir volontairement le processus", "Parce que les machines ne savent pas écrire"], answer: 0, tip: "Le saviez-vous ? Les meilleurs systèmes ne sont pas 100 % automatiques : vortx place un garde-fou humain sur les décisions à risque, le reste tourne tout seul." },
  { id: "ia-05", theme: "ia", q: "Qu'est-ce qu'un voicebot ?", options: ["Un assistant qui dialogue par la voix au téléphone", "Un haut-parleur connecté", "Un logiciel de montage audio", "Un casque anti-bruit"], answer: 0, tip: "Le saviez-vous ? Un voicebot peut qualifier un appel et prendre un rendez-vous 24h/24 — vos heures d'ouverture ne limitent plus vos prises de contact." },
  { id: "ia-06", theme: "ia", q: "L'IA générative est particulièrement utile pour…", options: ["Produire des premières versions de contenu à relire et affiner", "Garantir des chiffres comptables exacts sans contrôle", "Remplacer toute relecture humaine", "Signer vos contrats à votre place"], answer: 0, tip: "Le saviez-vous ? L'IA accélère la rédaction, mais la valeur reste dans l'angle et la relecture — vortx l'utilise comme un brouillon intelligent, jamais comme un publieur autonome." },
  { id: "ia-07", theme: "ia", q: "Que signifie « intégrer une API » dans un projet d'automatisation ?", options: ["Faire communiquer deux services entre eux de façon programmée", "Imprimer un document", "Créer une adresse e-mail", "Changer la couleur d'un bouton"], answer: 0, tip: "Le saviez-vous ? La plupart des outils que vous utilisez déjà exposent une API — vortx les relie pour que vos données circulent sans copier-coller." },
  { id: "ia-08", theme: "ia", q: "Quel indicateur traduit le mieux le ROI d'une automatisation ?", options: ["Le temps et les coûts économisés par rapport au manuel", "Le nombre de couleurs de l'interface", "La taille du fichier de configuration", "Le nombre de clics pour la lancer"], answer: 0, tip: "Le saviez-vous ? On mesure une automatisation en heures rendues à l'équipe — un audit vortx chiffre ce gain avant même de construire quoi que ce soit." },
  { id: "ia-09", theme: "ia", q: "Qu'est-ce qu'une « hallucination » d'un modèle d'IA ?", options: ["Une réponse fausse présentée avec assurance", "Un bug d'affichage à l'écran", "Une coupure de serveur", "Une option payante premium"], answer: 0, tip: "Le saviez-vous ? Brancher l'IA sur une base de connaissances vérifiée réduit fortement les hallucinations — c'est tout l'intérêt d'un assistant RAG bien câblé." },
  { id: "ia-10", theme: "ia", q: "Pourquoi connecter un chatbot à votre CRM ?", options: ["Pour enregistrer les leads et leur contexte automatiquement", "Pour augmenter la facture d'électricité", "Pour ralentir les réponses", "Pour supprimer vos contacts"], answer: 0, tip: "Le saviez-vous ? Un lead capté la nuit et déjà fiché dans votre CRM au réveil, c'est une relance qui part le matin plutôt que trois jours plus tard." },
  { id: "ia-11", theme: "ia", q: "Un « agent » IA se distingue d'un simple chatbot car il peut…", options: ["Enchaîner plusieurs étapes et utiliser des outils pour accomplir une tâche", "Uniquement dire bonjour", "Changer la police de votre site", "Fonctionner sans aucune instruction"], answer: 0, tip: "Le saviez-vous ? Un agent ne se contente pas de répondre : il agit (recherche, calcul, mise à jour). vortx en déploie avec des limites claires et traçables." },
  { id: "ia-12", theme: "ia", q: "Avant d'automatiser un processus, la meilleure première étape est de…", options: ["Cartographier le processus existant et ses points de friction", "Acheter le logiciel le plus cher", "Automatiser tout d'un coup sans test", "Supprimer le service concerné"], answer: 0, tip: "Le saviez-vous ? On n'automatise jamais un processus flou : vortx commence par le clarifier, puis l'outille — sinon on automatise le désordre." },
  { id: "lu-01", theme: "lu", q: "Quelles sont les trois langues administratives officielles du Luxembourg ?", options: ["Luxembourgeois, français, allemand", "Français, anglais, néerlandais", "Allemand, anglais, italien", "Luxembourgeois, anglais, portugais"], answer: 0, tip: "Le saviez-vous ? Une communication B2B au Luxembourg jongle souvent FR/DE/EN selon la cible — vortx construit dès le départ des sites pensés multilingues." },
  { id: "lu-02", theme: "lu", q: "À quoi sert l'attribut hreflang sur un site multilingue ?", options: ["Indiquer aux moteurs la langue et la région de chaque page", "Accélérer le chargement des images", "Changer la devise affichée", "Bloquer les robots"], answer: 0, tip: "Le saviez-vous ? Un hreflang mal réglé peut servir la version allemande à un francophone — un détail technique qui plombe l'expérience et le SEO local." },
  { id: "lu-03", theme: "lu", q: "Sous le RGPD, les cookies non essentiels (ex. publicité) nécessitent…", options: ["Le consentement préalable de l'internaute", "Aucune autorisation", "Un simple bandeau ignorable", "L'accord de la commune"], answer: 0, tip: "Le saviez-vous ? Au Luxembourg, la CNPD veille au consentement réel : un bandeau cookies conforme protège votre marque autant que vos visiteurs." },
  { id: "lu-04", theme: "lu", q: "Que désigne la « Grande Région » autour du Luxembourg ?", options: ["L'espace transfrontalier avec la Belgique, la France et l'Allemagne", "Un quartier de Luxembourg-Ville", "Une zone franche fiscale unique", "Le nom officiel du pays"], answer: 0, tip: "Le saviez-vous ? Une grande partie de la main-d'œuvre est frontalière — cibler la Grande Région élargit nettement votre audience B2B." },
  { id: "lu-05", theme: "lu", q: "Pour le SEO local au Luxembourg, quel signal pèse fortement ?", options: ["Une fiche Google Business Profile complète et à jour", "La longueur du nom de domaine", "Le nombre de polices utilisées", "La couleur des boutons"], answer: 0, tip: "Le saviez-vous ? Beaucoup de recherches locales se font sur mobile en déplacement — une fiche soignée capte ces intentions « près de moi » immédiates." },
  { id: "lu-06", theme: "lu", q: "Comment s'appelle l'autorité luxembourgeoise de protection des données ?", options: ["La CNPD", "La CSSF", "L'ILR", "La CNIL"], answer: 0, tip: "Le saviez-vous ? La CNPD est l'équivalent luxembourgeois de la CNIL française — vortx livre des sites pensés conformes dès la conception." },
  { id: "lu-07", theme: "lu", q: "Le luxembourgeois (Lëtzebuergesch) est-il utile en marketing local ?", options: ["Oui, il crée de la proximité, surtout en B2C et institutionnel", "Non, personne ne le parle", "Seulement à l'écrit administratif", "Uniquement pour les panneaux routiers"], answer: 0, tip: "Le saviez-vous ? Une accroche en luxembourgeois signale l'ancrage local — un atout d'image que vortx dose selon votre audience réelle." },
  { id: "lu-08", theme: "lu", q: "Pour cibler à la fois résidents et frontaliers, mieux vaut…", options: ["Adapter la langue et le message selon le segment", "Tout publier uniquement en anglais", "Ignorer les frontaliers", "Traduire mot à mot sans contexte"], answer: 0, tip: "Le saviez-vous ? Le bon réflexe n'est pas de tout traduire, mais d'adapter : vortx hiérarchise les langues selon là où sont vos clients." },
  { id: "lu-09", theme: "lu", q: "Quelle particularité B2B est marquante au Luxembourg ?", options: ["Un marché compact mais très international et concurrentiel", "Aucune entreprise étrangère", "Un seul secteur d'activité", "L'absence totale de digital"], answer: 0, tip: "Le saviez-vous ? Sur un marché petit et dense, la différenciation prime : un positionnement net vaut mieux qu'un message générique." },
  { id: "lu-10", theme: "lu", q: "Sous le RGPD, un « droit d'accès » permet à une personne de…", options: ["Demander quelles données vous détenez sur elle", "Accéder à vos locaux", "Modifier votre site web", "Obtenir une remise commerciale"], answer: 0, tip: "Le saviez-vous ? Pouvoir répondre vite à une demande d'accès suppose des données bien organisées — un CRM propre vous sauve la mise." },
  { id: "lu-11", theme: "lu", q: "Pour un site visant FR/DE/EN, la meilleure approche est de…", options: ["Prévoir l'architecture multilingue dès la conception", "Traduire à l'arrache après le lancement", "N'avoir qu'une seule langue figée", "Utiliser une traduction automatique non relue"], answer: 0, tip: "Le saviez-vous ? Bâtir le multilingue après coup coûte plus cher que de le prévoir — l'architecture des sites vortx l'intègre dès le départ." },
  { id: "lu-12", theme: "lu", q: "Pourquoi un domaine en .lu peut-il aider localement ?", options: ["Il renforce le signal d'ancrage et de confiance au Luxembourg", "Il améliore la vitesse du serveur", "Il rend le site gratuit", "Il supprime le besoin de RGPD"], answer: 0, tip: "Le saviez-vous ? Le .lu rassure sur l'ancrage local, mais ne remplace pas un bon contenu — c'est l'un des signaux, pas une formule magique." },
  { id: "lu-13", theme: "lu", q: "Une bonne pratique RGPD pour un formulaire de contact est de…", options: ["Ne collecter que les données réellement nécessaires", "Demander un maximum d'infos par précaution", "Cacher la finalité de la collecte", "Revendre les e-mails"], answer: 0, tip: "Le saviez-vous ? La minimisation des données est un principe du RGPD — moins de champs, c'est aussi un meilleur taux de conversion." },
  { id: "culture-01", theme: "culture", q: "Que signifie l'acronyme CTR ?", options: ["Click-Through Rate (taux de clic)", "Cost To Reach", "Customer Trust Ratio", "Content Tracking Report"], answer: 0, tip: "Le saviez-vous ? Le CTR mesure la part de gens qui cliquent après avoir vu votre annonce — un titre plus percutant le fait souvent grimper." },
  { id: "culture-02", theme: "culture", q: "Le ROAS sert à mesurer…", options: ["Le chiffre d'affaires généré par euro de publicité dépensé", "Le nombre d'abonnés", "La vitesse du site", "Le poids des images"], answer: 0, tip: "Le saviez-vous ? Un ROAS de 4 signifie 4 € gagnés par euro investi — vortx optimise les campagnes pour ce ratio, pas pour les vanity metrics." },
  { id: "culture-03", theme: "culture", q: "Quelle est la différence entre SEO et SEA ?", options: ["Le SEO est le référencement naturel, le SEA le référencement payant", "Le SEO est payant, le SEA gratuit", "Les deux désignent l'e-mailing", "Aucune, ce sont des synonymes"], answer: 0, tip: "Le saviez-vous ? SEO et SEA se complètent : le payant amorce vite, le naturel construit un actif durable — l'idéal est de combiner les deux." },
  { id: "culture-04", theme: "culture", q: "À quoi sert Google Tag Manager ?", options: ["Gérer les balises de suivi sans modifier le code à chaque fois", "Héberger des vidéos", "Rédiger des articles de blog", "Créer des factures"], answer: 0, tip: "Le saviez-vous ? Bien configuré, GTM permet de déclencher un suivi propre sans rappeler un développeur à chaque nouvelle campagne." },
  { id: "culture-05", theme: "culture", q: "Dans un entonnoir marketing, l'étape « TOFU » correspond à…", options: ["Le haut de l'entonnoir : la notoriété et la découverte", "La signature du contrat", "Le service après-vente", "La facturation"], answer: 0, tip: "Le saviez-vous ? Confondre haut et bas d'entonnoir fait dépenser au mauvais endroit — vortx adapte le message à chaque étape du parcours." },
  { id: "culture-06", theme: "culture", q: "Que mesure le CPC en publicité ?", options: ["Le coût par clic", "Le coût par client", "Le contenu par campagne", "Le clic par contact"], answer: 0, tip: "Le saviez-vous ? Un CPC bas n'est pas un but en soi : ce qui compte, c'est le coût d'acquisition d'un client réellement rentable." },
  { id: "culture-07", theme: "culture", q: "La notoriété (branding) et la conversion diffèrent car…", options: ["L'une fait connaître la marque, l'autre déclenche l'action d'achat", "Elles sont strictement identiques", "La conversion ne sert à rien", "La notoriété est interdite en B2B"], answer: 0, tip: "Le saviez-vous ? Une marque connue convertit mieux : la notoriété prépare le terrain que la conversion vient récolter." },
  { id: "culture-08", theme: "culture", q: "Le CPM correspond au coût pour…", options: ["Mille impressions d'une annonce", "Un million de clients", "Chaque conversion", "Une page modifiée"], answer: 0, tip: "Le saviez-vous ? Le CPM est l'unité reine des campagnes de notoriété, là où l'on cherche la visibilité plutôt que le clic immédiat." },
  { id: "culture-09", theme: "culture", q: "Un « taux de rebond » élevé sur une page indique souvent…", options: ["Que les visiteurs repartent sans interagir davantage", "Que le site charge trop vite", "Que vous avez trop de ventes", "Que la page est en plusieurs langues"], answer: 0, tip: "Le saviez-vous ? Un rebond élevé n'est pas toujours mauvais (une réponse trouvée vite), mais sur une landing, il signale un message à revoir." },
  { id: "culture-10", theme: "culture", q: "Quel format d'e-mailing respecte les bonnes pratiques actuelles ?", options: ["Une liste opt-in avec lien de désinscription clair", "Une liste achetée sans consentement", "Des objets trompeurs", "Aucun moyen de se désabonner"], answer: 0, tip: "Le saviez-vous ? Une base opt-in plus petite mais consentante surperforme presque toujours une grosse liste froide — qualité avant quantité." },
  { id: "culture-11", theme: "culture", q: "Que signifie un « KPI » ?", options: ["Indicateur clé de performance (Key Performance Indicator)", "Un type de cookie", "Un format d'image", "Un réseau social"], answer: 0, tip: "Le saviez-vous ? Trop de KPI tue le KPI : vortx en retient quelques-uns réellement liés à votre objectif business." },
  { id: "culture-12", theme: "culture", q: "L'A/B testing consiste à…", options: ["Comparer deux versions pour voir laquelle performe le mieux", "Traduire un site en deux langues", "Sauvegarder deux fois un fichier", "Acheter deux noms de domaine"], answer: 0, tip: "Le saviez-vous ? Tester un seul élément à la fois (titre, bouton, visuel) permet de savoir ce qui a vraiment fait bouger les chiffres." },
  { id: "culture-13", theme: "culture", q: "Le terme « GEO » (Generative Engine Optimization) désigne…", options: ["Optimiser sa visibilité dans les réponses des IA génératives", "Le géociblage publicitaire", "La géolocalisation GPS", "Un format vidéo"], answer: 0, tip: "Le saviez-vous ? Avec l'essor des moteurs IA, être cité dans leurs réponses devient un enjeu — vortx intègre déjà cette logique au SEO." },
  { id: "culture-14", theme: "culture", q: "Quel est l'intérêt d'un « appel à l'action » (CTA) clair ?", options: ["Indiquer au visiteur la prochaine étape à effectuer", "Décorer la page", "Ralentir la navigation", "Cacher l'offre"], answer: 0, tip: "Le saviez-vous ? Une page sans CTA évident laisse le visiteur partir : un seul bouton clair (« Réserver un appel ») bat dix liens dispersés." },
  { id: "culture-15", theme: "culture", q: "Pour piloter ses performances, Google Analytics 4 permet surtout de…", options: ["Suivre le comportement des visiteurs et les conversions", "Envoyer des newsletters", "Héberger le site", "Créer un logo"], answer: 0, tip: "Le saviez-vous ? Sans mesure, on optimise à l'aveugle — un suivi GA4 propre est la base de toute décision marketing chez vortx." },
];

/** FR is the source; other locales fall back to it until translated. */
const pool: Partial<Record<Locale, QuizQuestion[]>> = { fr };

/** Returns the question pool for a locale (falls back to French). */
export function getQuizQuestions(locale: Locale): QuizQuestion[] {
  return pool[locale] ?? fr;
}
